from dataclasses import dataclass

@dataclass
class ProviderRateLimitCheck:
    provider: str
    model: str
    current_tpm_limit: int
    current_rpm_limit: int
    required_tpm: float
    required_rpm: float

    @property
    def tpm_headroom_pct(self) -> float:
        return (1 - self.required_tpm / self.current_tpm_limit) * 100

    @property
    def rpm_headroom_pct(self) -> float:
        return (1 - self.required_rpm / self.current_rpm_limit) * 100

    def is_viable(self) -> bool:
        return self.tpm_headroom_pct > 20 and self.rpm_headroom_pct > 20

    def report(self) -> str:
        lines = [
            f"Provider: {self.provider} ({self.model})",
            f"  TPM: required={self.required_tpm:,.0f}  limit={self.current_tpm_limit:,}  headroom={self.tpm_headroom_pct:.0f}%",
            f"  RPM: required={self.required_rpm:,.0f}  limit={self.current_rpm_limit:,}  headroom={self.rpm_headroom_pct:.0f}%",
            f"  Viable: {'YES' if self.is_viable() else 'NO — requires tier upgrade or request routing'}",
        ]
        return "\n".join(lines)

check = ProviderRateLimitCheck(
    provider="OpenAI",
    model="gpt-4o",
    current_tpm_limit=800_000,       # Tier 5
    current_rpm_limit=10_000,
    required_tpm=fnol_throughput.total_peak_tps * 60,   # from earlier calculation
    required_rpm=fnol_throughput.peak_rps * 60,
)
print(check.report())

from dataclasses import dataclass

@dataclass
class LatencyBudget:
    e2e_p95_ms: int
    retrieval_p95_ms: int
    ttft_p95_ms: int
    guardrails_p95_ms: int

    @property
    def generation_budget_ms(self) -> int:
        return self.e2e_p95_ms - self.retrieval_p95_ms - self.ttft_p95_ms - self.guardrails_p95_ms

    def max_output_tokens(self, tokens_per_second: float = 40) -> int:
        budget_seconds = self.generation_budget_ms / 1000
        return int(budget_seconds * tokens_per_second)

fnol_budget = LatencyBudget(
    e2e_p95_ms=4000,
    retrieval_p95_ms=600,
    ttft_p95_ms=1200,
    guardrails_p95_ms=200,
)
print(f"Generation budget:  {fnol_budget.generation_budget_ms}ms")
print(f"Max output tokens:  {fnol_budget.max_output_tokens(tokens_per_second=40)}")
